import React, { useState } from 'react'
import {
  Paragraph,
  DialogOverlay,
  DialogOverlayActions,
  DialogOverlayFooter,
  Button,
  DangerButton,
  useStatusOverlay,
} from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { NoticeLoading } from '@fs/zion-icon'
import { useChatState } from '../providers/ChatStateProvider'
import { deleteMessage, deleteThreadParentMessage } from '../helpers/stream/streamChatHelper'
import { CHANNEL_TYPE, FS_THREAD_MESSAGE_PREFIX } from '../services/fsChat/fsChannelEnums'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import useChatLog from '../hooks/useChatLog'
import { LOG_LEVEL } from '../global/chatLog'

export default function ChatMessageDeleteDialog({ overlay, message }) {
  const [t] = useTranslation()
  const [loading, setLoading] = useState(false)
  const showStatusOverlay = useStatusOverlay()
  const { client } = useChatState()
  const { log, track } = useChatLog({ component: '[ChatMessageDeleteDialog]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  const handleDeleteClick = async () => {
    setLoading(true)
    try {
      // TODO: once fs_thread writes are removed, we don't need to check for fs_thread anymore.
      if (message.cid.startsWith(CHANNEL_TYPE.FS_THREAD) || message.parent_id) {
        // for replies to a thread only. The parent message will have the channel type of the channel it came from.
        track({ link_name: `Chat:Delete Message:Threaded` }, { chatMessageId: message.id, chatChannelId: message.cid })
        try {
          await deleteMessage({ client, messageId: `${FS_THREAD_MESSAGE_PREFIX}${message.id}` })
        } catch (e) {
          // This error will happen and the reply count will be out of sync if the parent message was previously deleted.
          log({
            msg: `Unable to delete secondary threaded message:${FS_THREAD_MESSAGE_PREFIX}${message.id}${e}`,
            level: LOG_LEVEL.ERROR,
          })
        }
      }
      if (message.reply_count - message.deleted_reply_count > 0) {
        // for parent messages of a thread
        track(
          { link_name: `Chat:Delete Message:Parent with ${message.reply_count} - replies` },
          { chatMessageId: message.id, chatChannelId: message.cid }
        )
        await deleteThreadParentMessage({ client, messageId: message.id })
      } else {
        track(
          { event_name: 'click_action', link_name: `Chat:Delete Message:Normal` },
          { chatMessageId: message.id, chatChannelId: message.cid }
        )
        await deleteMessage({ client, messageId: message.id })
      }
      showStatusOverlay({
        message: t('chat.message-delete-confirmation.label', 'Message Deleted'),
        type: 'success',
        dismissable: true,
      })
    } catch (e) {
      handleBasicError(e, {
        moreInfo: `Problem deleting message. ChannelId: ${message?.cid}, messageId: ${message?.id}`,
      })
    }
    setLoading(false)

    overlay.close()
  }

  return (
    <DialogOverlay title={t('chat.message-delete.label', 'Delete Message')} {...overlay} closeOnClickAway={false}>
      <Paragraph size="sm">
        {t(
          'chat.message-delete-confirmation.message',
          'Are you sure you want to delete this message? This cannot be undone.'
        )}
      </Paragraph>
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button onClick={() => overlay.close()}>{t('common-ui:cancel.action', 'Cancel')}</Button>
          <DangerButton
            test-dataid="message-delete"
            onClick={() => handleDeleteClick()}
            Icon={loading ? NoticeLoading : undefined}
          >
            {t('common-ui:delete.action', 'Delete')}
          </DangerButton>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
