import React, { useMemo } from 'react'
import { ListItem, MenuOverlay, useStatusOverlay, IconButton, Paragraph } from '@fs/zion-ui'
import {
  ContentCopy,
  ContentFlag,
  MenuMore,
  ContentDelete,
  ContentEdit,
  NoticeDoNot,
  DocumentFolderCollection,
} from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { copyToClipboard } from '@fs/zion-frontend-friends'
import { CHAT_MESSAGE_TYPE } from '../helpers/stream/streamChatHelper'
import { CHAT_ATTACHMENT_SERVICE_TYPE, getCanShowImage } from '../helpers/chatAttachmentHelper'
import useSaveToMemories from '../hooks/useSaveToMemories'
import { useChatState } from '../providers/ChatStateProvider'

function includesArtifact(attachments) {
  return attachments.some((attachment) => attachment.serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.ARTIFACT_STORE)
}

export default function ChatMessageMenuOverlay({
  message,
  deleteOverlay,
  editOverlay,
  reportAbuseOverlay,
  blockUserOverlay,
  fromUser,
  attachmentsWithData,
  formattedDistance,
  formattedTimestamp,
}) {
  const { client } = useChatState()
  const [t] = useTranslation()
  const showStatusOverlay = useStatusOverlay()
  const saveToMemories = useSaveToMemories()

  const canSaveImages = useMemo(() => {
    if (client?.anonymous) return false
    if (!attachmentsWithData) return false
    return Object.values(attachmentsWithData).every((attachment) => {
      return !!(attachment && getCanShowImage({ screeningState: attachment?.screeningState, fromUser }))
    })
  }, [attachmentsWithData, fromUser, client?.anonymous])

  return (
    <MenuOverlay
      menuButton={
        <IconButton
          title={t('chat.message-menu.aria-label', 'Chat Message Menu')}
          size="xs"
          Icon={MenuMore}
          aria-label={t('chat.message-menu.aria-label', 'Chat Message Menu')}
          data-testid="chat-message-menu"
        />
      }
      inline={false}
    >
      <ListItem
        primaryText={t('chat.copy-to-clipboard.label', 'Copy to Clipboard')}
        data-testid="copy-to-clipboard"
        onClick={() => {
          copyToClipboard(
            message?.text,
            'text/plain',
            () =>
              showStatusOverlay({
                message: t('chat.copied-to-clipboard.message', `Copied text "${message?.text}" to clipboard.`),
                type: 'success',
                dismissable: true,
              }),
            (e) =>
              showStatusOverlay({
                message: t('chat.copied-to-clipboard.failed.message', `Failed to copy text to clipboard. Error: ${e}`),
                type: 'error',
                dismissable: true,
              })
          )
        }}
        startElement={<ListItem.Icon Icon={ContentCopy} />}
      />

      {fromUser && !(message?.type === CHAT_MESSAGE_TYPE.DELETED && message.reply_count > 0) && (
        <ListItem
          data-testid="edit-message"
          onClick={editOverlay.handleClick}
          primaryText={t('chat.message-edit.label', 'Edit Message')}
          startElement={<ListItem.Icon Icon={ContentEdit} />}
        />
      )}
      {canSaveImages && message?.attachments && includesArtifact(message?.attachments) && (
        <ListItem
          data-testid="save-to-memories"
          onClick={() => saveToMemories(message?.attachments)}
          primaryText={t('chat.save-to-memories.label', 'Save to Memories')}
          startElement={<ListItem.Icon Icon={DocumentFolderCollection} />}
        />
      )}
      {fromUser && (
        <ListItem
          data-testid="delete-message"
          onClick={deleteOverlay.handleClick}
          primaryText={t('chat.message-delete.label', 'Delete Message')}
          startElement={<ListItem.Icon Icon={ContentDelete} />}
        />
      )}
      {!fromUser && (
        <ListItem
          data-testid="report-abuse"
          onClick={reportAbuseOverlay.handleClick}
          primaryText={t('common-ui:report-abuse.action', 'Report Abuse')}
          startElement={<ListItem.Icon Icon={ContentFlag} />}
        />
      )}
      {!fromUser && !client?.anonymous && (
        <ListItem
          data-testid="block-user"
          onClick={blockUserOverlay.handleClick}
          primaryText={t('chat.block-user.action', 'Block {name}', { name: message?.user?.name })}
          startElement={<ListItem.Icon Icon={NoticeDoNot} />}
        />
      )}
      <Paragraph aria-hidden="true" secondary size="xs" centered>
        <time dateTime={message?.created_at} title={formattedTimestamp}>
          {formattedDistance}
        </time>
      </Paragraph>
    </MenuOverlay>
  )
}
