import React, { useEffect, useRef, useState } from 'react'
import { DialogOverlay, DialogOverlayActions, DialogOverlayFooter, Button, useOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import ZionForm, { FormMultilineTextField, useZionForm } from '@fs/zion-form'
import { NoticeLoading } from '@fs/zion-icon'
import { useChatState } from '../providers/ChatStateProvider'
import { updateMessageText, CHAT_MESSAGE_TYPE } from '../helpers/stream/streamChatHelper'
import { CHANNEL_TYPE, MAX_LENGTH_MESSAGE } from '../services/fsChat/fsChannelEnums'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import ChatMessageDeleteDialog from './ChatMessageDeleteDialog'
import useChatLog from '../hooks/useChatLog'
import ChatEmojiButton from '../chat-buttons/ChatEmojiButton'
import { LOG_LEVEL } from '../global/chatLog'
import { useOnKeyDown } from '../helpers/chatActionsHelper'

export default function ChatMessageEditDialog({ overlay, message }) {
  const [t] = useTranslation()
  const deleteMessageOverlay = useOverlay()
  const { client } = useChatState()
  const [loading, setLoading] = useState(false)
  const { log, track } = useChatLog({ component: '[ChatMessageEditDialog]' })
  const { handleBasicError } = useHandleChatErrors({ log })
  const messageRef = useRef()

  const methods = useZionForm({
    mode: 'all',
    defaultValues: { messageText: message?.text },
  })
  const {
    formState: { isValid, isDirty },
    getValues,
  } = methods
  const enableSave = isDirty && isValid && !loading

  const handleSaveEditText = async (text) => {
    setLoading(true)

    try {
      if (message?.cid?.startsWith?.(CHANNEL_TYPE.FS_THREAD) || message?.parent_id) {
        const threadMessageId = message.id.split(':')[1]
        try {
          track(
            { event_name: 'click_action', link_name: `Chat:Edit Message:Threaded` },
            { chatMessageId: message.id, chatChannelId: message.cid }
          )
          await updateMessageText({ client, messageId: threadMessageId, text })
        } catch (e) {
          // This error will happen and the reply message text will not be updated if the parent message was previously deleted.
          log({
            msg: `Unable to edit the secondary threaded message:${threadMessageId}${e}`,
            level: LOG_LEVEL.ERROR,
          })
        }
      }
      track(
        { event_name: 'click_action', link_name: `Chat:Edit Message:Normal` },
        { chatMessageId: message.id, chatChannelId: message.cid }
      )
      await updateMessageText({ client, messageId: message.id, text })
      overlay.close()
    } catch (e) {
      handleBasicError(e, {
        moreInfo: `Problem editing message. ChannelId: ${message?.cid}, messageId: ${message?.id}`,
      })
    }
    setLoading(false)
  }

  useEffect(() => {
    setTimeout(() => {
      messageRef?.current?.focus()
    }, 300)
  }, [messageRef])

  useEffect(() => {
    if (message.state === CHAT_MESSAGE_TYPE.DELETED) {
      overlay.close()
    }
  }, [message, overlay])

  const handleSubmit = () => {
    const values = getValues()
    if (!values?.messageText) {
      deleteMessageOverlay.handleClick()
    } else {
      handleSaveEditText(values?.messageText)
    }
  }

  return (
    <>
      <DialogOverlay
        title={t('chat.message-edit.label', 'Edit Message')}
        {...overlay}
        as={ZionForm}
        methods={methods}
        onSubmit={handleSubmit}
        closeOnClickAway={false}
      >
        <FormMultilineTextField
          data-testid="message-edit-textfield"
          autoFocus
          ref={messageRef}
          name="messageText"
          placeholder={t('chat.message-edit.placeholder', 'Edit Message')}
          maxLength={MAX_LENGTH_MESSAGE}
          aria-label={t('chat.message-edit.placeholder', 'Edit Message')}
          onKeyDown={useOnKeyDown({ isValid: enableSave, onSubmit: handleSubmit })}
        />
        <DialogOverlayFooter>
          <DialogOverlayActions>
            <ChatEmojiButton textFieldRef={messageRef} />
            <div growX />
            <Button onClick={() => overlay.close()}>{t('common-ui:cancel.action', 'Cancel')}</Button>
            <Button type="submit" emphasis="high" disabled={!enableSave} Icon={loading ? NoticeLoading : undefined}>
              {t('common-ui:save.action', 'Save')}
            </Button>
          </DialogOverlayActions>
        </DialogOverlayFooter>
      </DialogOverlay>
      <ChatMessageDeleteDialog message={message} overlay={deleteMessageOverlay} />
    </>
  )
}
