import React, { Suspense } from 'react'
import { useTranslation } from 'react-i18next'
import { useOverlay } from '@fs/zion-ui'
import { i18n } from '@fs/zion-locale'
import { baseUrl } from '@fs/zion-config'
import ChatMessageDeleteDialog from './ChatMessageDeleteDialog'
import ChatMessageEditDialog from './ChatMessageEditDialog'
import ChatMessageMenuOverlay from './ChatMessageMenuOverlay'
import { cisIdFromChatUserId } from '../helpers/stream/streamChatHelper'
import { useChatState } from '../providers/ChatStateProvider'
import useChatLog from '../hooks/useChatLog'
import { LOG_LEVEL } from '../global/chatLog'

const ReportAbuseOverlay = React.lazy(() => import('@fs/zion-report-abuse-overlay'))
const ChatBlockUserOverlay = React.lazy(() => import('../chat-window/chat-window-chats/ChatBlockUserOverlay'))

ReportAbuseOverlay.displayName = 'ReportAbuseOverlay'
ChatBlockUserOverlay.displayName = 'ChatBlockUserOverlay'

function getDisplayName(message) {
  const displayName = message?.user?.name || message?.user?.id
  if (displayName && displayName !== 'undefined') {
    return displayName
  }
  return i18n.t('chat.unknown-name.label', 'Unknown Name')
}

function getDMConsoleLink({ message, cisId, pid }) {
  if (!pid) {
    const trimmedCisId = cisId?.replace('cis.user.', '')
    const url = `${baseUrl}/dmconsole/user/${trimmedCisId}/messages?context=cisUserId&messageId=${message?.id}`
    return `[DM Console](${encodeURI(url)})`
  }

  const url = `${baseUrl}/dmconsole/chat/${message?.cid}/messages?messageId=${message?.id}`
  return `[DM Console](${encodeURI(url)})`
}

export default function ChatMessageOverlay({
  message,
  fromUser,
  pid,
  attachmentsWithData,
  formattedDistance,
  formattedTimestamp,
}) {
  const [t] = useTranslation()
  const { client } = useChatState()
  const { log } = useChatLog({ component: '[ChatMessageOverlay]' })
  const deleteMessageOverlay = useOverlay()
  const editMessageOverlay = useOverlay()
  const reportAbuseOverlay = useOverlay()
  const blockUserOverlay = useOverlay()
  const displayName = getDisplayName(message)
  const cisId = message?.user?.id && cisIdFromChatUserId(message?.user?.id)
  const dmConsoleLink = getDMConsoleLink({ message, cisId, pid })
  const reportAbuseAdditionalInfo =
    `Reported message_id: ${message?.id}\n` +
    `Message channel CID: ${message?.cid}\n` +
    `Sender user_id: ${message?.user?.id}\n` +
    `Sender CIS ID: ${cisId}\n` +
    `Sender name: ${displayName}\n` +
    `Message sent at: ${new Date(message.created_at).toUTCString()}\n` +
    `Message text: ${message?.text}\n\n${dmConsoleLink}`
  const flagMessage = async () => {
    try {
      await client.flagMessage(message.id)
    } catch (error) {
      log({ msg: `Failed to flag message ${message.id} after abuse report was created`, level: LOG_LEVEL.ERROR })
    }
  }

  return (
    <>
      <ChatMessageMenuOverlay
        message={message}
        deleteOverlay={deleteMessageOverlay}
        editOverlay={editMessageOverlay}
        reportAbuseOverlay={reportAbuseOverlay}
        blockUserOverlay={blockUserOverlay}
        fromUser={fromUser}
        attachmentsWithData={attachmentsWithData}
        formattedDistance={formattedDistance}
        formattedTimestamp={formattedTimestamp}
      />
      <Suspense fallback={<div>{t('common-ui:loading.ellipsis.label', 'Loading...')}</div>}>
        {(deleteMessageOverlay.isOpen || deleteMessageOverlay.transitioning) && fromUser && (
          <ChatMessageDeleteDialog overlay={deleteMessageOverlay} message={message} />
        )}
        {(editMessageOverlay.isOpen || editMessageOverlay.transitioning) && fromUser && (
          <ChatMessageEditDialog overlay={editMessageOverlay} message={message} />
        )}
        {!fromUser && (
          <ReportAbuseOverlay
            overlay={reportAbuseOverlay}
            subject="Report Abuse for Chat"
            additionalInfo={reportAbuseAdditionalInfo}
            onReportCreated={flagMessage}
          />
        )}
        {(blockUserOverlay.isOpen || blockUserOverlay.transitioning) && !fromUser && (
          <ChatBlockUserOverlay overlay={blockUserOverlay} targetUser={message?.user} />
        )}
      </Suspense>
    </>
  )
}
