import { useCallback } from 'react'
import { useTranslation } from 'react-i18next'
import axios from '@fs/zion-axios'
import { useStatusOverlay } from '@fs/zion-ui'
import useChatLog from './useChatLog'
import chatLog, { LOG_LEVEL } from '../global/chatLog'
import { uploadToMemories } from '../services/memories/memoriesService'
import { CHAT_ATTACHMENT_SERVICE_TYPE } from '../helpers/chatAttachmentHelper'

function parse409ResponseJson(response) {
  // Extract JSON substring from the response
  const jsonStart = response.indexOf('{')
  const jsonEnd = response.lastIndexOf('}') + 1
  const jsonString = response.slice(jsonStart, jsonEnd)

  return JSON.parse(jsonString)
}

async function fetchArtifactBlobData(artifact) {
  const url = `/service/msg-artifact/msg-attach/${artifact?.id}`
  try {
    const response = await axios.get(url, { responseType: 'blob' })
    return response
  } catch (err) {
    chatLog({
      msg: `Failed to fetch memory blob data: ${err}`,
      component: '[useSaveToMemories.fetchArtifactBlobData]',
      level: LOG_LEVEL.ERROR,
    })
    throw new Error('Failed to fetch memory blob data')
  }
}

export default function useSaveToMemories() {
  const [t] = useTranslation()
  const { log } = useChatLog({ component: '[useSaveToMemories]' })
  const showStatusOverlay = useStatusOverlay()

  return useCallback(
    async (attachments) => {
      try {
        const artifactsBlobData = await Promise.all(
          attachments
            .filter((attachment) => attachment?.serviceType === CHAT_ATTACHMENT_SERVICE_TYPE.ARTIFACT_STORE)
            .map((artifact) => fetchArtifactBlobData(artifact))
        )
        const memoryIds = []
        showStatusOverlay({
          message: t('chat.save-to-memories.saving', 'Saving to Memories...'),
          type: 'normal',
          dismissable: true,
          transient: true,
        })
        await Promise.all(
          artifactsBlobData.map(async (result) => {
            const uploadedMemory = await uploadToMemories(result.data)
            memoryIds.push(uploadedMemory?.artifact?.id)
          })
        )
        showStatusOverlay({
          message: t('chat.save-to-memories.success', 'Saved to Memories'),
          type: 'success',
          transient: true,
          actionLabel: t('chat.save-to-memories.action', 'View'),
          // Since multiple artifacts are saved in one call, the view link can just go to the first one
          actionCallback: () => window.open(`/photos/artifacts/${memoryIds[0]}?c=my-memories`, '_blank'),
        })
      } catch (error) {
        if (error?.response?.status === 409) {
          const errorObject = parse409ResponseJson(error.response.data.message)
          const id = errorObject.artifact[0]?.id
          const url = id ? `/photos/artifacts/${id}?c=my-memories` : '/photos/gallery'
          showStatusOverlay({
            message: t('chat.save-to-memories.duplicate', 'Memory already saved'),
            type: 'normal',
            transient: true,
            actionLabel: t('chat.save-to-memories.action', 'View'),
            actionCallback: () => window.open(url, '_blank'),
          })
          return
        }
        log({
          msg: `Failed to save to Memories: ${error}`,
          level: LOG_LEVEL.ERROR,
        })
        showStatusOverlay({
          message: t('chat.save-to-memories.failed', 'Failed to save to Memories'),
          type: 'error',
          transient: true,
          dismissable: true,
        })
      }
    },
    [showStatusOverlay, t, log]
  )
}
